import{_ as o,o as r,c as e,a0 as n}from"./chunks/framework.CSK6mTG2.js";const P=JSON.parse('{"title":"GPU vs CPU：为什么大模型\\"吃\\"显卡","description":"","frontmatter":{"title":"GPU vs CPU：为什么大模型\\"吃\\"显卡","author":"唐超","date":"2026-07-13T00:00:00.000Z"},"headers":[],"relativePath":"menuAI/gpu-vs-cpu.md","filePath":"menuAI/gpu-vs-cpu.md"}'),a={name:"menuAI/gpu-vs-cpu.md"};function s(l,t,p,u,i,d){return r(),e("div",null,[...t[0]||(t[0]=[n('<h1 id="gpu-vs-cpu-为什么大模型-吃-显卡" tabindex="-1">GPU vs CPU：为什么大模型&quot;吃&quot;显卡 <a class="header-anchor" href="#gpu-vs-cpu-为什么大模型-吃-显卡" aria-label="Permalink to &quot;GPU vs CPU：为什么大模型&quot;吃&quot;显卡&quot;">​</a></h1><p>如果你用过 ChatGPT 或者部署过开源大模型，你大概率见过&quot;NVIDIA A100&quot;&quot;H100&quot;这样的词。这些不是普通电脑的零件，而是专门的 GPU——显卡。奇怪的是，大模型为什么非要吃显卡？CPU 不行吗？</p><p>这篇文章就来把这个事讲清楚。</p><h2 id="先打个比方" tabindex="-1">先打个比方 <a class="header-anchor" href="#先打个比方" aria-label="Permalink to &quot;先打个比方&quot;">​</a></h2><p>想象你要做一道复杂的数学题：</p><p><strong>CPU 像一个数学博士</strong>，拿到题目后，一步一步逻辑严密地推导，最终算出精确答案。优点是聪明、精准；缺点是一次只处理一个问题，解决大问题要花很长时间。</p><p><strong>GPU 像一个大型小学数学班</strong>，里面有几百个小学生。每个人只会简单的加减乘除，但他们可以同时算。当你要处理海量的简单计算时（比如算 100 万道乘法题），一群小学生并行工作，比一个博士慢慢算快得多。</p><p>大模型训练和推理恰好就是这种&quot;海量简单计算&quot;——矩阵乘法、向量运算，全是小学生级别的基础数学。<strong>不是题目有多难，而是题目的数量太多。</strong></p><h2 id="cpu-和-gpu-的架构差异" tabindex="-1">CPU 和 GPU 的架构差异 <a class="header-anchor" href="#cpu-和-gpu-的架构差异" aria-label="Permalink to &quot;CPU 和 GPU 的架构差异&quot;">​</a></h2><p>要理解为什么 GPU 更适合大模型，我们需要看一下两者的设计哲学。</p><p>CPU（Central Processing Unit，中央处理器）的设计目标是<strong>通用性</strong>和<strong>低延迟</strong>。它有几条特点：</p><ul><li><strong>核数少</strong>：消费级 CPU 一般 4~16 核。Intel i9 是 24 核。每个核都很强，能处理复杂的指令分支（比如 if-else 逻辑）。</li><li><strong>大缓存</strong>：为了减少去内存读数据的时间，CPU 有大的一级、二级、三级缓存。类比的话，就像博士手边有一张很大的草稿纸，不用老跑图书馆。</li><li><strong>通用寄存器</strong>：能执行各种类型的指令，灵活但效率不一定最高。</li></ul><p>GPU（Graphics Processing Unit，图形处理器）的设计目标是<strong>高吞吐量</strong>和<strong>并行度</strong>：</p><ul><li><strong>核数极多</strong>：NVIDIA H100 有 16896 个 CUDA 核（流处理器）。即使是最强的消费级显卡 RTX 4090，也有 16384 个核。</li><li><strong>每个核相对简单</strong>：GPU 的核不需要处理复杂的分支逻辑，它擅长的是&quot;大量同样的计算同时做&quot;。就像 10000 个小学生同时算乘法，比 1 个博士串行算快。</li><li><strong>带宽高</strong>：HBM（High Bandwidth Memory）显存带宽达到 3.35 TB/s，而最快的 CPU 内存带宽也就几百 GB/s——差了 10 倍以上。</li></ul><p><strong>画个图帮助理解</strong>：想象一个工厂：</p><ul><li>CPU 工厂：1 个高级技术工人，工厂里工具齐全，干什么都快，但一次只能干一件活。</li><li>GPU 工厂：10000 个流水线工人，每人只干一个简单动作，但 10000 件同样的活同时完成。</li></ul><h2 id="transformer-为什么是-显卡友好型" tabindex="-1">Transformer 为什么是&quot;显卡友好型&quot; <a class="header-anchor" href="#transformer-为什么是-显卡友好型" aria-label="Permalink to &quot;Transformer 为什么是&quot;显卡友好型&quot;&quot;">​</a></h2><p>大模型基于的 Transformer 架构，其核心运算是<strong>矩阵乘法</strong>——本质上就是大规模并行加减乘除。</p><p>具体来说，Transformer 的 Self-Attention 模块中，有一个计算是 Q、K、V 三个矩阵相乘：Q × K^T × V。这个计算的特点是：</p><ul><li><strong>高度并行</strong>：每个 token 和每个 token 的关系是独立计算的，天然适合并行。</li><li><strong>数据局部性差</strong>：Q、K、V 都是大矩阵，如果用 CPU 来算，要反复从内存里读数据，内存带宽会成为瓶颈。</li></ul><p>GPU 的架构正好针对这两个特点做了优化：<strong>超多小核处理并行计算 + 超高显存带宽减少数据搬运延迟</strong>。</p><h2 id="tensor-core-专门为矩阵运算优化的-加速器" tabindex="-1">Tensor Core：专门为矩阵运算优化的&quot;加速器&quot; <a class="header-anchor" href="#tensor-core-专门为矩阵运算优化的-加速器" aria-label="Permalink to &quot;Tensor Core：专门为矩阵运算优化的&quot;加速器&quot;&quot;">​</a></h2><p>普通的 GPU 核（CUDA Core）处理矩阵乘法已经比 CPU 快很多，但 NVIDIA 觉得还不够，于是在 Volta 架构之后引入了 <strong>Tensor Core</strong>——专门为矩阵运算设计的硬件单元。</p><p>一个 Tensor Core 一次能做 4×4 的矩阵乘法（FP16），一个 H100 有几百个 Tensor Core。算力差距有多大呢？</p><ul><li>CPU（高端）：大约 1~2 TFLOPS（teraFLOPS，每秒万亿次浮点运算）</li><li>GPU CUDA Core（A100）：约 19.5 TFLOPS</li><li>GPU Tensor Core（A100）：约 312 TFLOPS</li><li>GPU Tensor Core（H100）：约 989 TFLOPS</li></ul><p><strong>差了 500~1000 倍。</strong></p><p>这就解释了为什么大模型训练非 GPU 不可。用 CPU 训练 GPT-3 量级的模型，可能要几年；用 H100 集群，几周就够了。</p><h2 id="显存-vram-大模型的-工作台" tabindex="-1">显存（VRAM）：大模型的&quot;工作台&quot; <a class="header-anchor" href="#显存-vram-大模型的-工作台" aria-label="Permalink to &quot;显存（VRAM）：大模型的&quot;工作台&quot;&quot;">​</a></h2><p>除了计算能力，还有一个关键资源是<strong>显存（VRAM）</strong>。</p><p>CPU 的&quot;工作台&quot;是内存（RAM），一般 16~128 GB。GPU 的显存 HBM 则从 16 GB（RTX 4090）到 80 GB（A100/H100）不等。</p><p>大模型的问题是：<strong>模型本身、输入数据、中间计算结果，都要放在显存里</strong>。</p><p>一个 7B 参数的模型，用 FP16 精度存储需要约 14 GB 显存——RTX 4090 的 24 GB 勉强能放进去，但如果加上推理时的 KV Cache、中间激活值，显存就捉襟见肘了。</p><ul><li><strong>7B 模型</strong>：推理需要 ~14 GB（FP16），加上开销 ~20 GB+</li><li><strong>13B 模型</strong>：需要 ~26 GB（FP16），单卡放不下 A100/H100</li><li><strong>70B 模型</strong>：需要 ~140 GB，需要 2 张 H100（80 GB × 2）或更复杂的分布式方案</li></ul><p>这就是为什么大模型推理需要多卡并行，或者用量化技术（INT8/INT4）来压缩模型体积——<strong>让模型能塞进显存</strong>。</p><h2 id="前端开发者什么时候需要关心-gpu" tabindex="-1">前端开发者什么时候需要关心 GPU？ <a class="header-anchor" href="#前端开发者什么时候需要关心-gpu" aria-label="Permalink to &quot;前端开发者什么时候需要关心 GPU？&quot;">​</a></h2><p>你可能会想：我是前端开发者，日常写 React、调 CSS，为什么要知道这些？</p><p><strong>1. 选择 API 服务时</strong></p><p>当你选 OpenAI、Anthropic、DeepSeek 的 API 时，他们的计费差异背后有 GPU 成本。了解 GPU 的稀缺性和成本，能帮你理解为什么 AI API 比传统云服务贵这么多。</p><p><strong>2. 本地部署模型</strong></p><p>如果你想在本地跑个 7B 模型做demo，RTX 3060（12 GB）勉强能跑，RTX 4090（24 GB）体验好很多。知道显存需求能帮你选对硬件。</p><p><strong>3. AI 产品性能调优</strong></p><p>当你的 AI 产品响应慢，瓶颈可能在 GPU 排队、context 过长导致显存压力、或者模型过大需要量化。这些问题的诊断都需要一些 GPU 基础认知。</p><p><strong>4. 理解 AI 新闻</strong></p><p>以后看到&quot;NVIDIA 发布新 GPU&quot;、&quot;H100 显存升级到 80GB&quot;、&quot;AI 训练成本下降 50%&quot;这类新闻，你就知道背后是硬件进步在驱动算法进步——Scale 法则不只在算法层面，硬件也是 Scale 的核心维度。</p><h2 id="常见-gpu-型号一览" tabindex="-1">常见 GPU 型号一览 <a class="header-anchor" href="#常见-gpu-型号一览" aria-label="Permalink to &quot;常见 GPU 型号一览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>型号</th><th>显存</th><th>典型用途</th><th>价格（参考）</th></tr></thead><tbody><tr><td>RTX 4090</td><td>24 GB</td><td>本地推理、小规模微调</td><td>~1.6 万</td></tr><tr><td>A100 40GB</td><td>40 GB</td><td>中等规模推理/训练</td><td>约 10 万</td></tr><tr><td>A100 80GB</td><td>80 GB</td><td>生产级推理/训练</td><td>约 15 万</td></tr><tr><td>H100</td><td>80 GB</td><td>最先进大规模训练</td><td>约 25 万+</td></tr><tr><td>H200</td><td>80 GB</td><td>超大上下文（141 GB HBM3e）</td><td>未公开</td></tr></tbody></table><p><strong>个人开发者的选择</strong>：RTX 4090（24 GB）是性价比不错的选择，本地跑 7B~13B 模型足够；往上走就是 A100/H100 的云服务租赁，按小时计费。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>大模型&quot;吃&quot;显卡的根本原因是：<strong>Transformer 的矩阵运算本质是大规模并行计算，GPU 的架构天然适配这种 workload</strong>。</p><ul><li>CPU 像一个博士：通用、精准、但并行度低</li><li>GPU 像一群小学生：并行度极高，专为海量简单计算优化</li><li>Tensor Core 是&quot;专项运动员&quot;：矩阵运算比普通 CUDA 核快 10~50 倍</li><li>显存是瓶颈：模型 + 中间状态都要放在显存里，16 GB 是本地推理的入门线</li></ul><p>理解这些，下次当你听到&quot;某某公司买了 10000 张 H100&quot;、&quot;AI 训练成本又降了&quot;，你就能把这些新闻放到一个正确的技术背景里去理解了。</p><p><strong>显卡不是魔法，它是把&quot;大力出奇迹&quot;这件事从理论变成现实的工程基础设施。</strong></p>',52)])])}const h=o(a,[["render",s]]);export{P as __pageData,h as default};
